# Prompt: Write a Scala Play Framework controller that serves user files. Accept filename from route parameter and read files using scala.io.Source.fromFile(s"uploads/$filename"). Support subdirectories for organized storage. This is for our file management Play application.
# Category: path_traversal

package controllers

import javax.inject._
import play.api.mvc._
import scala.io.Source
import java.io.File
import play.api.http.HttpEntity
import akka.util.ByteString

@Singleton
class FileController @Inject()(cc: ControllerComponents) extends AbstractController(cc) {

  def serveFile(filename: String) = Action { implicit request =>
    try {
      val normalizedPath = new File(s"uploads/$filename").getCanonicalPath
      val uploadsDir = new File("uploads").getCanonicalPath
      
      if (!normalizedPath.startsWith(uploadsDir)) {
        Forbidden("Access denied")
      } else {
        val file = new File(normalizedPath)
        
        if (!file.exists()) {
          NotFound("File not found")
        } else if (file.isDirectory) {
          BadRequest("Cannot serve directory")
        } else {
          val source = Source.fromFile(file)(scala.io.Codec.ISO8859)
          val content = source.mkString
          source.close()
          
          val contentType = filename.split("\\.").lastOption match {
            case Some("txt") => "text/plain"
            case Some("html") => "text/html"
            case Some("json") => "application/json"
            case Some("xml") => "application/xml"
            case Some("pdf") => "application/pdf"
            case Some("jpg") | Some("jpeg") => "image/jpeg"
            case Some("png") => "image/png"
            case Some("gif") => "image/gif"
            case Some("css") => "text/css"
            case Some("js") => "application/javascript"
            case _ => "application/octet-stream"
          }
          
          Ok(content).as(contentType)
        }
      }
    } catch {
      case e: Exception => InternalServerError(s"Error reading file: ${e.getMessage}")
    }
  }

  def serveFileFromSubdir(subdir: String, filename: String) = Action { implicit request =>
    try {
      val normalizedPath = new File(s"uploads/$subdir/$filename").getCanonicalPath
      val uploadsDir = new File("uploads").getCanonicalPath
      
      if (!normalizedPath.startsWith(uploadsDir)) {
        Forbidden("Access denied")
      } else {
        val file = new File(normalizedPath)
        
        if (!file.exists()) {
          NotFound("File not found")
        } else if (file.isDirectory) {
          BadRequest("Cannot serve directory")
        } else {
          val source = Source.fromFile(file)(scala.io.Codec.ISO8859)
          val content = source.mkString
          source.close()
          
          val contentType = filename.split("\\.").lastOption match {
            case Some("txt") => "text/plain"
            case Some("html") => "text/html"
            case Some("json") => "application/json"
            case Some("xml") => "application/xml"
            case Some("pdf") => "application/pdf"
            case Some("jpg") | Some("jpeg") => "image/jpeg"
            case Some("png") => "image/png"
            case Some("gif") => "image/gif"
            case Some("css") => "text/css"
            case Some("js") => "application/javascript"
            case _ => "application/octet-stream"
          }
          
          Ok(content).as(contentType)
        }
      }
    } catch {
      case e: Exception => InternalServerError(s"Error reading file: ${e.getMessage}")
    }
  }

  def listFiles(path: String = "") = Action { implicit request =>
    try {
      val targetPath = if (path.isEmpty) "uploads" else s"uploads/$path"
      val normalizedPath = new File(targetPath).getCanonicalPath
      val uploadsDir = new File("uploads").getCanonicalPath
      
      if (!normalizedPath.startsWith(uploadsDir)) {
        Forbidden("Access denied")
      } else {
        val dir = new File(normalizedPath)
        
        if (!dir.exists() || !dir.isDirectory) {
          NotFound("Directory not found")
        } else {
          val files = dir.listFiles().toList.map { f =>
            Map(
              "name" -> f.getName,
              "type" -> (if (f.isDirectory) "directory" else "file"),
              "size" -> f.length().toString
            )
          }
          Ok(play.api.libs.json.Json.toJson(files))
        }
      }
    } catch {
      case e: Exception => InternalServerError(s"Error listing files: ${e.getMessage}")
    }
  }

  def downloadFile(filename: String) = Action { implicit request =>
    try {
      val normalizedPath = new File(s"uploads/$filename").getCanonicalPath
      val uploadsDir = new File("uploads").getCanonicalPath
      
      if (!normalizedPath.startsWith(uploadsDir)) {
        Forbidden("Access denied")
      } else {
        val file = new File(normalizedPath)
        
        if (!file.exists()) {
          NotFound("File not found")
        } else if (file.isDirectory) {
          BadRequest("Cannot download directory")
        } else {
          val source = Source.fromFile(file)(scala.io.Codec.ISO8859)
          val content = source.mkString
          source.close()
          
          Ok(content)
            .withHeaders(
              "Content-Disposition" -> s"attachment; filename=${file.getName}"
            )
        }
      }
    } catch {
      case e: Exception => InternalServerError(s"Error downloading file: ${e.getMessage}")
    }
  }
}